args.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?player WHERE {
  ?player wdt:P1127 wd:Q15022551;  # position = center
          wdt:P166 wd:Q21622687;   # won NBA MVP
          wdt:P2048 ?height;
          wdt:P186 wd:Q495029.     # played in NBA
  FILTER(?height < 2.0828)
}
